mapper.select:

SELECT *
FROM NC.reference
WHERE dictionary = #{dictionary}
AND sort BETWEEN
(
    SELECT MAX(sort) FROM NC.reference
    WHERE dictionary = #{dictionary}
    AND sort <=
    (
      SELECT sort FROM NC.reference
      WHERE dictionary = #{dictionary}
      AND sort = #{sort}
      LIMIT 1
    )
    AND content = '/FRONT/'
)
AND
(
    SELECT MIN(sort) FROM NC.reference
    WHERE dictionary = #{dictionary}
    AND sort >=
    (
       SELECT sort FROM NC.reference
       WHERE dictionary = #{dictionary}
       AND sort = #{sort}
       LIMIT 1
    )
    AND content = '/END/'
)
ORDER BY sort;

SELECT * FROM NC.reference
WHERE dictionary = #{dictionary}
AND sort ${before ? '<' : '>'} #{sort}
ORDER BY sort ${before ? 'DESC' : 'ASC'}
LIMIT 1

