SELECT * FROM NC.reference
WHERE dictionary = #{dictionary}
AND content LIKE CONCAT('%', #{query}, '%')-- 粗篩：至少包含關鍵字（減少數據量）
AND content REGEXP CONCAT('\\{[+]?', '', #{query}, '', '\\}')
AND NOT content REGEXP CONCAT('\\{-', #{query}, '\\}')
ORDER BY LOCATE(CONCAT('{', #{query}, '}'), content);
